<script setup>
import { computed,ref } from 'vue';import { Head,Link } from '@inertiajs/vue3';import axios from 'axios';
const props=defineProps({participations:Array,definitions:Array,events:Array});const items=ref([...props.events]);const latest=(p,d)=>items.value.filter(e=>Number(e.project_person_id)===Number(p.id)&&e.definition_key===d.key).sort((a,b)=>new Date(b.occurred_at)-new Date(a.occurred_at))[0];const definitionsFor=(p)=>props.definitions.filter(d=>Number(d.project_id)===Number(p.projekt_id));const act=async(p,d,action)=>{const r=await axios.post(route('participant-portal.consents.act',d.id),{project_person_id:p.id,action,confirmed:true});items.value.push(r.data.event);};
</script>
<template><Head title="Einwilligungen"/><main class="min-h-screen bg-sky-50 px-5 py-8"><div class="mx-auto max-w-5xl space-y-6"><header class="flex justify-between"><div><p class="text-xs font-semibold uppercase tracking-widest text-zbb">Matrix Teilnehmerportal</p><h1 class="text-2xl font-bold">Einwilligungen und Freigaben</h1></div><Link :href="route('participant-portal.dashboard')" class="rounded border bg-white px-4 py-2">Dashboard</Link></header><section v-for="p in participations" :key="p.id" class="rounded-2xl border bg-white p-6 shadow"><h2 class="text-lg font-semibold">{{ p.projekt.name }}</h2><div class="mt-4 space-y-4"><article v-for="d in definitionsFor(p)" :key="d.id" class="rounded-xl border p-5"><div class="flex justify-between"><div><h3 class="font-semibold">{{ d.title }} <span v-if="d.required" class="text-xs text-red-600">Pflichtnachweis</span></h3><p class="text-xs text-gray-500">Version {{ d.version }}</p></div><span class="text-sm" :class="latest(p,d)?.action==='accepted'&&latest(p,d)?.definition_version===d.version?'text-green-700':'text-amber-700'">{{ latest(p,d)?.action==='accepted'&&latest(p,d)?.definition_version===d.version?'Zugestimmt':'Offen / widerrufen' }}</span></div><p class="mt-3 text-sm font-medium">Zweck</p><p class="text-sm text-gray-600">{{ d.purpose }}</p><details class="mt-3 rounded bg-gray-50 p-3"><summary class="cursor-pointer text-sm font-medium">Vollständigen Text anzeigen</summary><p class="mt-3 whitespace-pre-wrap text-sm text-gray-700">{{ d.content }}</p></details><label class="mt-4 flex gap-2 text-sm"><input type="checkbox" :checked="latest(p,d)?.action==='accepted'&&latest(p,d)?.definition_version===d.version" disabled/>Ich habe den Text gelesen.</label><div class="mt-3 flex gap-2"><button v-if="!(latest(p,d)?.action==='accepted'&&latest(p,d)?.definition_version===d.version)" class="rounded bg-green-600 px-4 py-2 text-white" @click="act(p,d,'accepted')">Zustimmen</button><button v-if="latest(p,d)?.action==='accepted'&&d.allow_withdrawal" class="rounded border border-red-500 px-4 py-2 text-red-600" @click="act(p,d,'withdrawn')">Widerrufen</button></div></article><p v-if="!definitionsFor(p).length" class="text-sm text-gray-500">Keine Einwilligungen hinterlegt.</p></div></section></div></main></template>
